@QCoDeS/core

Sometimes it's interesting to generate a list of events instead of a list of dates. For example:

```python
from dateutil.rrule import *
from dateutil.parser import *

import pprint
import sys
sys.displayhook = pprint.pprint


# EXAMPLE 1


def custom_event(date):
    return {'event': 'hola', 'date': date}

list(rrule(DAILY, count=10, dtstart=parse("19970902T090000"), event_wrapper=custom_event))

# EXAMPLE 2

class CustomEvent(object):
    def __init__(self, event_data):
        self.event_data = event_data
    
    def __call__(self, date):
        return {'title': self.event_data.get('title', None), 'date': date}

event_wrapper = CustomEvent({'title': 'Reminder'})

list(rrule(DAILY, count=10, dtstart=parse("19970902T090000"), event_wrapper=event_wrapper))

# EXAMPLE 3

class CustomEvent(dict):
    def __lt__(self, other):
        return self['date'] < other['date']
    
    def __gt__(self, other):
        return self['date'] > other['date']

class CustomEventWrapper(object):
    def __init__(self, event_data):
        self.event_data = event_data
    
    def __call__(self, date):
        return CustomEvent({'title': self.event_data.get('title', None), 'date': date})

event1 = CustomEventWrapper({'title': 'event1'})
event2 = CustomEventWrapper({'title': 'event2'})

rules = rruleset()
rules.rrule(rrule(DAILY, count=10, dtstart=parse("19970902T090000"), event_wrapper=event1))
rules.rrule(rrule(DAILY, count=10, dtstart=parse("19970904T090000"), event_wrapper=event2))
list(rules)
```

Hi there,
In our project we use single model with 2 roles like in this snippet:

```python
    class Address(Model):
        class Options:
            roles = {
                'full': whitelist('street', 'zipcode'),
                'short': whitelist('street')
            }
        zipcode = StringType(required=True)
        street = StringType(required=True)

    class User(Model):
        class Options:
            roles = {
                'full': whitelist('name', 'age', 'address'),
                'short': whitelist('name', 'address')
            }
        name = StringType(required=True)
        age = IntType(required=True)
        address = ModelType(Address, required=True)
```
And I can not understand why there is no validation using some role. 
When role=short I think that validation should be done without exceptions for such json: 
```javascript
 {
        'name': 'Bob',
        'address': {
            'street': 'somewhere in the world'
        }
}
```
